void MapBasedPredictionNode::mapCallback(const LaneletMapBin::ConstSharedPtr msg)
{
  RCLCPP_DEBUG(get_logger(), "[Map Based Prediction]: Start loading lanelet");
  lanelet_map_ptr_ = autoware::experimental::lanelet2_utils::remove_const(
    autoware::experimental::lanelet2_utils::from_autoware_map_msgs(*msg));

  auto routing_graph_and_traffic_rules =
    autoware::experimental::lanelet2_utils::instantiate_routing_graph_and_traffic_rules(
      lanelet_map_ptr_);

  routing_graph_ptr_ =
    autoware::experimental::lanelet2_utils::remove_const(routing_graph_and_traffic_rules.first);
  traffic_rules_ptr_ = routing_graph_and_traffic_rules.second;

  lru_cache_of_convert_path_type_.clear();  // clear cache
  RCLCPP_DEBUG(get_logger(), "[Map Based Prediction]: Map is loaded");

  predictor_vru_->setLaneletMap(lanelet_map_ptr_);
}

lanelet::LaneletMapConstPtr from_autoware_map_msgs(
  const autoware_map_msgs::msg::LaneletMapBin & msg)
{
  std::string data_str;
  data_str.assign(msg.data.begin(), msg.data.end());

  std::stringstream ss;
  ss << data_str;
  boost::archive::binary_iarchive oa(ss);

  auto lanelet_map_ptr = std::make_shared<lanelet::LaneletMap>();
  oa >> *lanelet_map_ptr;
  lanelet::Id id_counter = 0;
  oa >> id_counter;
  lanelet::utils::registerId(id_counter);

  return lanelet_map_ptr;
}

instantiate_routing_graph_and_traffic_rules(
  lanelet::LaneletMapConstPtr lanelet_map, const char * location, const char * participant)
{
  auto traffic_rules = lanelet::traffic_rules::TrafficRulesFactory::create(location, participant);
  return {
    lanelet::routing::RoutingGraph::build(*lanelet_map, *traffic_rules), std::move(traffic_rules)};
}

void PredictorVru::setLaneletMap(std::shared_ptr<lanelet::LaneletMap> lanelet_map_ptr)
{
  std::unique_ptr<ScopedTimeTrack> st_ptr;
  if (time_keeper_) st_ptr = std::make_unique<ScopedTimeTrack>(__func__, *time_keeper_);

  lanelet_map_ptr_ = std::move(lanelet_map_ptr);

  const auto all_lanelets = lanelet::utils::query::laneletLayer(lanelet_map_ptr_);
  const auto crosswalks = lanelet::utils::query::crosswalkLanelets(all_lanelets);
  const auto walkways = lanelet::utils::query::walkwayLanelets(all_lanelets);
  crosswalks_.clear();
  crosswalks_.insert(crosswalks_.end(), crosswalks.begin(), crosswalks.end());
  crosswalks_.insert(crosswalks_.end(), walkways.begin(), walkways.end());

  lanelet::LineStrings3d fences;
  for (const auto & linestring : lanelet_map_ptr_->lineStringLayer) {
    if (const std::string type = linestring.attributeOr(lanelet::AttributeName::Type, "none");
        type == "fence") {
      fences.emplace_back(std::const_pointer_cast<lanelet::LineStringData>(linestring.constData()));
    }
  }
  fence_layer_ = lanelet::utils::createMap(fences);
}
